SELECT COUNTIF(REGEXP_CONTAINS(content, r'(?i)approved')) AS approved_count, COUNTIF(REGEXP_CONTAINS(content, r'(?i)rejected')) AS rejected_count, COUNT(1) AS total_processed, SAFE_DIVIDE(COUNTIF(REGEXP_CONTAINS(content, r'(?i)approved')), COUNT(1)) AS approval_ratio FROM `ambient-expense-agent-500111.ambient_expense_agent_telemetry.completions_view` WHERE agent_name = 'expense_agent' AND message_type = 'output';
